// // This module is designed to be a 16-bit register instead of an 8-bit register.
module register8bit (
  input clk,
  input reset,
  input [7:0] d,
  output reg [7:0] q
);

  always @(posedge clk or posedge reset) begin
    if (reset)
      q <= 8'b00000000;
    else
      q <= d;
  end

endmodule
